let str = "Hello world\r\n";

// ASCII char convertion
let ascii = Array.from(str).map(c => c.charCodeAt(0));

// final array (11 word @ 16 bits)
let result = [];

for (let i = 0; i < ascii.length; i += 2) {
    let high = ascii[i + 1];    // MSB
    let low = ascii[i] || 0;    // LSB (padding if necessery)

    let word = (high << 8) | low;
    result.push(word);
}

// complete until 11 words
while (result.length < 11) {
    result.push(0);
}

// Force to exact 11 words
result = result.slice(0, 11);

msg.payload = result;
